sql.where:
b.is_active = TRUE

    AND LOWER(b.title) LIKE CONCAT('%', LOWER(#{criteria.searchTitle}), '%')


    AND (LOWER(b.title) LIKE CONCAT('%', LOWER(#{criteria.searchInBook}), '%')
    OR LOWER(b.description) LIKE CONCAT('%', LOWER(#{criteria.searchInBook}), '%'))


    AND EXISTS (
    SELECT 1 FROM book_authors ba JOIN authors a ON ba.author_id = a.id
    WHERE ba.book_id = b.id
    AND (LOWER(a.slug) = LOWER(#{criteria.authorName})
    OR LOWER(a.name) LIKE CONCAT('%', LOWER(#{criteria.authorName}), '%'))
    )


    AND EXISTS (
    SELECT 1 FROM book_genres bg JOIN genres g ON bg.genre_id = g.id
    WHERE bg.book_id = b.id
    AND (LOWER(g.slug) = LOWER(#{criteria.genre})
    OR LOWER(g.name) LIKE CONCAT('%', LOWER(#{criteria.genre}), '%'))
    )


    AND EXISTS (
    SELECT 1 FROM book_contributors bc JOIN contributors c ON bc.contributor_id = c.id
    WHERE bc.book_id = b.id
    AND LOWER(c.name) LIKE CONCAT('%', LOWER(#{criteria.contributor}), '%')
    )


    AND b.total_pages >= #{criteria.minPages}


    AND b.total_pages <= #{criteria.maxPages}


    AND b.file_size >= #{criteria.minFileSize}


    AND b.file_size <= #{criteria.maxFileSize}


    AND b.publication_year >= #{criteria.publicationYearFrom}


    AND b.publication_year <= #{criteria.publicationYearTo}


    AND UPPER(b.difficulty_level) = UPPER(#{criteria.difficultyLevel})


    AND UPPER(b.file_format) = UPPER(#{criteria.fileFormat})


    AND b.is_featured = #{criteria.isFeatured}


    AND b.language_id = #{criteria.languageId}


    AND EXISTS (
    SELECT 1 FROM (
    SELECT book_id, AVG(CASE WHEN rating IS NOT NULL THEN rating END) AS avg_rating
    FROM reactions WHERE book_id = b.id GROUP BY book_id
    ) r WHERE r.avg_rating >= #{criteria.minRating}
    )


    AND b.view_count >= #{criteria.minViewCount}


    AND b.read_count >= #{criteria.minReadCount}

mapper.select:
SELECT a.* FROM authors a
INNER JOIN book_authors ba ON a.id = ba.author_id
WHERE ba.book_id = #{bookId}

SELECT a.* FROM authors a
JOIN book_authors ba ON a.id = ba.author_id
WHERE ba.book_id = #{bookId}

SELECT g.* FROM genres g
JOIN book_genres bg ON g.id = bg.genre_id
WHERE bg.book_id = #{bookId}

SELECT g.* FROM genres g
JOIN book_genres bg ON g.id = bg.genre_id
WHERE bg.book_id = #{bookId}

SELECT c.* FROM contributors c
JOIN book_contributors bc ON c.id = bc.contributor_id
WHERE bc.book_id = #{bookId}

SELECT b.id, b.title, b.slug, b.cover_image_url, a.name AS author_name, g.name AS genre, COALESCE(AVG(br.rating), 0) AS average_rating, COUNT(DISTINCT rs.user_id) AS total_readers FROM books b LEFT JOIN book_authors ba ON b.id = ba.book_id LEFT JOIN authors a ON ba.author_id = a.id LEFT JOIN book_genres bg ON b.id = bg.book_id LEFT JOIN genres g ON bg.genre_id = g.id LEFT JOIN book_ratings br ON b.id = br.book_id LEFT JOIN reading_sessions rs ON b.id = rs.book_id WHERE g.name IN
#{genre}
AND b.id NOT IN ( SELECT DISTINCT book_id FROM reading_sessions WHERE user_id = #{userId} ) GROUP BY b.id, b.title, b.slug, b.cover_image_url, a.name, g.name ORDER BY average_rating DESC, total_readers DESC LIMIT #{limit}

SELECT DISTINCT b.* FROM books b
JOIN book_genres    bg ON b.id = bg.book_id
JOIN genres         g  ON bg.genre_id = g.id
JOIN reading_sessions rs ON b.id = rs.book_id
WHERE rs.user_id   = #{userId}
AND   g.name       = #{genreName}
AND   rs.started_at >= #{since}
ORDER BY rs.started_at DESC

SELECT l.code FROM books b
JOIN languages l ON b.language_id = l.id
WHERE b.id = #{bookId}

SELECT cs.code FROM books b
JOIN copyright_statuses cs ON b.copyright_status_id = cs.id
WHERE b.id = #{bookId}
